VALUES
  ('elementary-f29af906-moex-00308', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例最新規定，私法人買受供住宅使用之房屋，下列敘述何者錯誤？', '["應檢具使用計畫，經中央主管機關許可", "中央主管機關許可之文件，有效期限為1年", "私法人取得供住宅使用之房屋，於登記完畢後3年內不得辦理移轉、讓與或預告登記", "私法人因強制執行、徵收、法院判決或其他法律規定仍得辦理移轉"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00309', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市更新條例規定，實施者擬訂或變更都市更新事業計畫報核時，應經一定比率之私有土地與私 有合法建築物所有權人數及所有權面積之同意，若不予計算人數，最低之同意比率應為下列何者？', '["私有土地及私有合法建築物所有權面積均超過四分之三同意", "私有土地及私有合法建築物所有權面積均超過十分之九同意", "私有土地及私有合法建築物所有權面積均超過五分之四同意", "私有土地及私有合法建築物所有權面積均超過二分之一同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00310', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '都市計畫公共設施保留地，在保留期間仍為建築使用者，除自用住宅用地外，統按多少計徵地價稅？', '["千分之二", "千分之四", "千分之六", "千分之十"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00311', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法第34條之規定，土地所有權人出售其自用住宅用地者，下列有關土地增值稅之敘述，何 者錯誤？', '["都市土地面積未超過3公畝部分或非都市土地面積未超過7公畝部分，統就該部分之土地漲價總 數額按百分之十徵收之；超過3公畝或7公畝者，其超過部分之土地漲價總數額，依第33條規定 之稅率徵收之", "第一項土地於出售前1年內，曾供營業使用或出租者，不適用第一項規定", "第一項規定於自用住宅之評定現值不及所占基地公告土地現值百分之二十者，不適用之。但自用住 宅建築工程完成滿1年以上者不在此限", "土地所有權人，依第一項規定稅率繳納土地增值稅者，以一次為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00312', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依平均地權條例第47條之4之規定，有關預售屋或新建成屋買賣契約之買受人於簽訂買賣契約後之 敘述，下列何者錯誤？', '["不得讓與或轉售買賣契約與第三人", "配偶、直系血親或二親等內旁系血親間之讓與或轉售，不在此限", "預售屋或新建成屋買賣契約之買受人，經中央主管機關核准後，得讓與或轉售買賣契約與第三人", "買受人依第一項但書後段規定得讓與或轉售之戶（棟）數，全國每2年以一戶（棟）為限"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00313', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，徵用土地之每年使用補償費，依徵用公告期滿第15日之何種地價百分之十 計算？', '["公告土地現值", "公告地價", "市價", "協議價格"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00314', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例規定，實施區段徵收時，有關原土地所有權人申請發給抵價地之敘述，何者錯誤？', '["應於徵收公告期間內，檢具有關證明文件，以書面向該管直轄巿或縣（巿）主管機關申請之", "依規定申請發給抵價地時，得就其全部或部分被徵收土地應領之補償地價提出申請", "經核定發給抵價地之土地所有權人，不得向直轄巿或縣（巿）主管機關申請改按原徵收補償地價發 給現金補償", "經核定發給抵價地者，若未按指定期限接管者，視為已接管"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00315', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地徵收條例第50條規定，下列有關撤銷或廢止徵收之敘述，何者錯誤？', '["撤銷或廢止徵收，由需用土地人向中央主管機關申請之", "需用土地人未申請撤銷或廢止徵收者，原土地所有權人得向該管直轄巿或縣（巿）主管機關請求之", "該管直轄巿或縣（巿）主管機關收受第二項請求後，應會同需用土地人及其他有關機關審查", "依同條例第51條規定，中央主管機關於核准撤銷或廢止徵收後，應將原案通知原土地所有權人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00316', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '繼承人有數人時，下列何者須全體繼承人之同意始得為之？', '["申請為繼承土地公同共有之登記", "申請為繼承土地分別共有之登記", "申請為繼承土地設定地上權之登記", "申請為繼承土地標示分割變更之登記"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00317', 'elementary-f29af906', 'elementary-f29af906-moex-113-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地稅法規定，土地所有權人辦理土地移轉繳納土地增值稅時，在其持有土地期間內，因重新規定 地價增繳之地價稅，就其移轉土地部分，准予抵繳其應納之土地增值稅。准予抵繳之總額，下列何者 正確？', '["以不超過土地移轉時應繳增值稅總額百分之五為限", "以不超過土地移轉時應繳增值稅總額百分之六為限", "以不超過土地移轉時應繳增值稅總額百分之七為限", "以不超過土地移轉時應繳增值稅總額百分之八為限"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:52+00:00", "source_pdf_sha1": "12de481d6766", "answer_pdf_sha1": "7f4421ce65b7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "513", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
